array_filter( $options, function ( $item ) use ( $filter ) {

                // No filters - return all
                if ( empty( $filter ) ) {
                    return true;
                }

                foreach ( $filter as $key => $value ) {

                    if ( ! isset( $item[ $key ] ) ) {
                        return false;
                    }

                    // Support arrays OR scalars
                    if ( is_array( $item[ $key ] ) ) {
                        if ( ! in_array( $value, $item[ $key ], true ) ) {
                            return false;
                        }
                    } else {
                        if ( $item[ $key ] !== $value ) {
                            return false;
                        }
                    }
                }

                return true;
            })

